import React, { useState } from "react";
import FileUpload from "./components/FileUpload";
import SearchBar from "./components/SearchBar";
import ResultsTable from "./components/ResultsTable";
import DownloadButton from "./components/DownloadButton";
import { parseCsv, filterCsvRows, toCsv, CsvRow } from "./utils/csvUtils";
import "./App.css";

const ROWS_PER_PAGE = 20;

const App: React.FC = () => {
  const [csvRows, setCsvRows] = useState<CsvRow[]>([]);
  const [filteredRows, setFilteredRows] = useState<CsvRow[]>([]);
  const [keyword, setKeyword] = useState<string>("");
  const [csvLoaded, setCsvLoaded] = useState<boolean>(false);
  const [currentPage, setCurrentPage] = useState<number>(1);

  const handleFileSelected = async (file: File) => {
    try {
      const rows = await parseCsv(file);
      setCsvRows(rows);
      setFilteredRows(rows);
      setCsvLoaded(true);
      setKeyword("");
      setCurrentPage(1);
    } catch (error) {
      alert("Erro ao ler o arquivo CSV.");
      setCsvLoaded(false);
    }
  };

  const handleKeywordChange = (value: string) => {
    setKeyword(value);
    const filtered = filterCsvRows(csvRows, value);
    setFilteredRows(filtered);
    setCurrentPage(1);
  };

  const handlePageChange = (page: number) => {
    setCurrentPage(page);
  };

  return (
    <div className="container">
      <h1>Easy Labeling</h1>
      <FileUpload onFileSelected={handleFileSelected} />
      {csvLoaded && (
        <>
          <SearchBar keyword={keyword} onKeywordChange={handleKeywordChange} />
          <ResultsTable
            rows={filteredRows}
            currentPage={currentPage}
            rowsPerPage={ROWS_PER_PAGE}
            onPageChange={handlePageChange}
          />
          <DownloadButton
            csvContent={toCsv(filteredRows)}
            disabled={filteredRows.length === 0}
          />
        </>
      )}
    </div>
  );
};

export default App;
